INSERT INTO postmaster_schema.postmaster_config_master ("key", value, created_at, updated_at, description) 
VALUES (
	'jolt.app.listener.notification', 
	'[
  {
    "operation": "default",
    "spec": {
      "appId": "AIRTELWORK",
      "metaInfo": {
        "createdDateTime": "NA"
      }
    }
  },
  {
    "operation": "shift",
    "spec": {
      "*": "&",
      "metaInfo": {
        "*": "metaInfo.&",
        "createdDateTime": {
          "NA": {
            "@(4,createdDateTime)": "metaInfo.createdDateTime"
          },
          "*": {
            "$": "metaInfo.createdDateTime"
          }
        }
      }
    }
  },
  {
    "operation": "shift",
    "spec": {
      "fcmId": "token",
      "topic": "topic",
      "workFlow": "workflow",
      "appVersion": "deviceAttributes.meta.&0",
      "*": "&"
    }
  },
  {
    "operation": "shift",
    "spec": {
      "metaInfo": {
        "actionButton": "actionn",
        "url": "data.value",
        "*": "data.&"
      },
      "*": "&"
    }
  },
  {
    "operation": "shift",
    "spec": {
      "actionn": "metaInfo.actionButton",
      "*": "&"
    }
  },
  {
    "operation": "shift",
    "spec": {
      "title": [
        "title",
        "apns.payload.aps.alert.title"
      ],
      "message": [
        "message",
        "apns.payload.aps.alert.body"
      ],
      "data": {
        "sound": [
          "data.sound",
          "apns.payload.aps.sound"
        ],
        "badge": [
          "data.badge",
          "apns.payload.aps.badge"
        ],
        "*": "data.&"
      },
      "*": "&"
    }
  },
  {
    "operation": "modify-overwrite-beta",
    "spec": {
      "data": {
        "badge": "=toInteger(@(1,badge))"
      },
      "apns": {
        "payload": {
          "aps": {
            "badge": "=toInteger(@(1,badge))"
          }
        }
      }
    }
  },
  {
    "operation": "shift",
    "spec": {
      "msisdn": "msisdn[]",
      "*": "&"
    }
  },
  {
    "operation": "sort"
  }
]', 
